CODE_EXAMPLE:
// Before
class Person {
  String name;
  String areaCode;
  String number;
  String getPhoneNumber() { return areaCode + number; }
}

// After
class Person {
  String name;
  Telephone telephone;
}

class Telephone {
  String areaCode;
  String number;
  String getPhoneNumber() { return areaCode + number; }
}

UNIT_TEST_EXAMPLE:
@Test
public void testExtractClass() {
  Person person = new Person("John");
  Telephone tel = new Telephone("415", "9999999");
  person.setTelephone(tel);

  assertEquals("4159999999", person.getTelephone().getPhoneNumber());
}
